# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;

class WebsitePreviewController extends Controller
{
    public function fetchPreview(Request $request)
    {
        $url = $request->input('url');
        
        if (empty($url)) {
            return response()->json(['error' => 'URL is required'], 400);
        }

        $cacheKey = 'preview_' . md5($url);
        
        $preview = Cache::remember($cacheKey, 3600, function () use ($url) {
            return $this->getWebsitePreview($url);
        });

        if (isset($preview['error'])) {
            return response()->json($preview, 400);
        }

        return response()->json($preview);
    }

    private function getWebsitePreview($url)
    {
        $ch = curl_init();
        
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_MAXREDIRS, 5);
        curl_setopt($ch, CURLOPT_TIMEOUT, 30);
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
        curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36');
        
        $html = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $error = curl_error($ch);
        
        curl_close($ch);

        if ($error) {
            return ['error' => 'Failed to fetch URL: ' . $error];
        }

        if ($httpCode !== 200) {
            return ['error' => 'HTTP error: ' . $httpCode];
        }

        return $this->parseHtmlContent($html, $url);
    }

    private function parseHtmlContent($html, $url)
    {
        $preview = [
            'url' => $url,
            'title' => '',
            'description' => '',
            'image' => '',
            'site_name' => '',
            'type' => 'website'
        ];

        libxml_use_internal_errors(true);
        $dom = new \DOMDocument();
        @$dom->loadHTML(mb_convert_encoding($html, 'HTML-ENTITIES', 'UTF-8'));
        libxml_clear_errors();

        $xpath = new \DOMXPath($dom);

        $ogTitle = $xpath->query('//meta[@property="og:title"]/@content');
        if ($ogTitle->length > 0) {
            $preview['title'] = $ogTitle->item(0)->nodeValue;
        }

        $ogDescription = $xpath->query('//meta[@property="og:description"]/@content');
        if ($ogDescription->length > 0) {
            $preview['description'] = $ogDescription->item(0)->nodeValue;
        }

        $ogImage = $xpath->query('//meta[@property="og:image"]/@content');
        if ($ogImage->length > 0) {
            $preview['image'] = $this->normalizeUrl($ogImage->item(0)->nodeValue, $url);
        }

        $ogSiteName = $xpath->query('//meta[@property="og:site_name"]/@content');
        if ($ogSiteName->length > 0) {
            $preview['site_name'] = $ogSiteName->item(0)->nodeValue;
        }

        $ogType = $xpath->query('//meta[@property="og:type"]/@content');
        if ($ogType->length > 0) {
            $preview['type'] = $ogType->item(0)->nodeValue;
        }

        if (empty($preview['title'])) {
            $twitterTitle = $xpath->query('//meta[@name="twitter:title"]/@content');
            if ($twitterTitle->length > 0) {
                $preview['title'] = $twitterTitle->item(0)->nodeValue;
            }
        }

        if (empty($preview['description'])) {
            $twitterDescription = $xpath->query('//meta[@name="twitter:description"]/@content');
            if ($twitterDescription->length > 0) {
                $preview['description'] = $twitterDescription->item(0)->nodeValue;
            }
        }

        if (empty($preview['image'])) {
            $twitterImage = $xpath->query('//meta[@name="twitter:image"]/@content');
            if ($twitterImage->length > 0) {
                $preview['image'] = $this->normalizeUrl($twitterImage->item(0)->nodeValue, $url);
            }
        }

        if (empty($preview['title'])) {
            $titleTag = $xpath->query('//title');
            if ($titleTag->length > 0) {
                $preview['title'] = $titleTag->item(0)->nodeValue;
            }
        }

        if (empty($preview['description'])) {
            $metaDescription = $xpath->query('//meta[@name="description"]/@content');
            if ($metaDescription->length > 0) {
                $preview['description'] = $metaDescription->item(0)->nodeValue;
            }
        }

        if (empty($preview['image'])) {
            $firstImage = $xpath->query('//img/@src');
            if ($firstImage->length > 0) {
                $preview['image'] = $this->normalizeUrl($firstImage->item(0)->nodeValue, $url);
            }
        }

        $preview['title'] = trim($preview['title']);
        $preview['description'] = trim($preview['description']);

        if (strlen($preview['description']) > 300) {
            $preview['description'] = substr($preview['description'], 0, 297) . '...';
        }

        return $preview;
    }

    private function normalizeUrl($imageUrl, $baseUrl)
    {
        if (filter_var($imageUrl, FILTER_VALIDATE_URL)) {
            return $imageUrl;
        }

        $parsedBase = parse_url($baseUrl);
        $scheme = $parsedBase['scheme'] ?? 'http';
        $host = $parsedBase['host'] ?? '';

        if (strpos($imageUrl, '//') === 0) {
            return $scheme . ':' . $imageUrl;
        }

        if (strpos($imageUrl, '/') === 0) {
            return $scheme . '://' . $host . $imageUrl;
        }

        $path = $parsedBase['path'] ?? '/';
        $path = substr($path, 0, strrpos($path, '/') + 1);

        return $scheme . '://' . $host . $path . $imageUrl;
    }

    public function showPreview(Request $request)
    {
        $url = $request->input('url');
        
        if (empty($url)) {
            return view('preview.form');
        }

        $preview = $this->fetchPreview($request)->getData();

        return view('preview.show', compact('preview', 'url'));
    }
}